// ─── Scoring ───
function scoreEdu(responses){
  let comp=0,tw=0;const results={};
  for(const sec of EDU_SECTIONS){
    const ans=sec.questions.filter(q=>responses[q.id]!==undefined);
    const raw=ans.reduce((s,q)=>s+(responses[q.id]??0),0);
    const mp=ans.length*4;const norm=mp>0?Math.round((raw/mp)*100):0;
    results[sec.id]={name:sec.name,score:norm,weight:sec.weight,answered:ans.length,total:sec.questions.length};
    comp+=norm*sec.weight;tw+=sec.weight;
  }
  const final=tw>0?Math.round(comp/tw):0;
  const mat=MATURITY.find(m=>final>=m.floor&&final<=m.ceiling)||MATURITY[0];
  return{composite:final,maturity:mat,sections:results};
}

