// PAGE: INSIGHT HUB
// ═══════════════════════════════════════════════════════════════════
const CAT_COLORS={Education:"#3B82F6",Business:"#F97316","Sector Spotlight":"#8B5CF6","Regional / Policy":"#10B981"};
const INSIGHT_CATS=["All","Education","Business","Sector Spotlight","Regional / Policy"];
const ARTICLE_IMAGES={"the-two-shocks":"./the-two-shocks.jpg","ai-in-fe-why-some-colleges-are-racing-ahead-while-others-stall":"./ai-in-fe.jpg","how-smes-can-escape-the-ai-fumble-period":"./sme-fumble.jpg","robotics-in-construction-why-the-west-midlands-needs-a-skills-pipeline-now":"./robotics-construction.jpg","the-west-midlands-skills-landscape-where-the-opportunities-are-in-2026":"./wm-skills.jpg","what-the-growth-and-skills-levy-means-for-smes":"./growth-levy.jpg","why-every-college-needs-an-ai-strategy-before-ofsted-expects-one":"./ofsted-ai.jpg","youth-unemployment-at-161-what-the-data-really-tells-us":"./youth-unemployment.jpg","what-employers-really-want-in-2026-ai-literacy-is-now-a-hiring-filter":"./employers-want.jpg","the-ai-skills-boost-is-free-training-enough":"./ai-skills-boost.jpg","the-dfes-quiet-revolution-ai-product-safety-standards-are-now-mandatory":"./dfe-safety.jpg"};

const IMG_WWD_HERO = "./what-we-do-hero.jpg";
const IMG_WWD_PATHWAY = "./what-we-do-pathway.jpg";
const fmtDate=(d)=>{if(!d)return"";const dt=new Date(d+"T00:00:00");return dt.toLocaleDateString("en-GB",{day:"numeric",month:"long",year:"numeric"});};

function InsightHub({onNav}){
  const[activeCat,setActiveCat]=useState("All");
  const featured=ARTICLES.find(a=>a.featured);
  const filtered=activeCat==="All"?ARTICLES.filter(a=>!a.featured):ARTICLES.filter(a=>!a.featured&&a.category===activeCat);
  const showFeatured=activeCat==="All"||featured?.category===activeCat;

  return(<div>
    {/* Hero */}
    <section style={{padding:"72px 0 48px",background:`linear-gradient(180deg,${C.nm} 0%,${C.navy} 100%)`}}>
      <div className="responsive-container" style={{maxWidth:800}}>
        <SL text="PROVIO Insight"/>
        <h1 className="fu1" style={{fontFamily:"Montserrat",fontSize:"clamp(32px,4.5vw,48px)",fontWeight:700,lineHeight:1.1,letterSpacing:"-0.03em",marginBottom:16}}>Intelligence for the <span style={{color:C.teal}}>AI Transition</span></h1>
        <p className="fu2" style={{fontSize:"clamp(15px,1.2vw,18px)",color:C.w6,maxWidth:580,lineHeight:1.7}}>Evidence-based analysis on how AI is reshaping education, business, and the labour market. Research you can act on.</p>
      </div>
    </section>

    {/* Category filter */}
    <section style={{borderTop:`1px solid ${C.w05}`,borderBottom:`1px solid ${C.w05}`,background:C.nm}}>
      <div className="responsive-container" style={{padding:"16px 80px",display:"flex",gap:6,flexWrap:"wrap"}}>
        {INSIGHT_CATS.map(cat=>{const isActive=activeCat===cat;const cc=cat==="All"?C.teal:(CAT_COLORS[cat]||C.teal);return(<button key={cat} onClick={()=>setActiveCat(cat)} style={{padding:"7px 18px",borderRadius:20,fontSize:12,fontWeight:isActive?600:400,cursor:"pointer",fontFamily:"Open Sans",transition:"all .2s",background:isActive?cc+"18":"transparent",border:`1px solid ${isActive?cc+"40":C.w05}`,color:isActive?cc:C.w4}} onMouseOver={e=>{if(!isActive){e.currentTarget.style.borderColor=cc+"30";e.currentTarget.style.color=cc;}}} onMouseOut={e=>{if(!isActive){e.currentTarget.style.borderColor=C.w05;e.currentTarget.style.color=C.w4;}}}>{cat}</button>);})}
      </div>
    </section>

    <div className="responsive-section responsive-container">
      {/* Featured article */}
      {showFeatured&&featured&&<div onClick={()=>onNav("article/"+featured.slug)} style={{padding:0,borderRadius:14,background:C.nc,border:`1px solid ${C.w05}`,cursor:"pointer",marginBottom:48,overflow:"hidden",transition:"all .25s"}} onMouseOver={e=>{e.currentTarget.style.borderColor=C.teal+"40";e.currentTarget.style.transform="translateY(-2px)";}} onMouseOut={e=>{e.currentTarget.style.borderColor=C.w05;e.currentTarget.style.transform="translateY(0)";}}>
        <div className="responsive-grid-2-24" style={{padding:0}}>
          <div style={{padding:"36px 36px 36px 36px",display:"flex",flexDirection:"column",justifyContent:"center"}}>
            <div style={{display:"flex",gap:10,alignItems:"center",marginBottom:14}}>
              <span style={{display:"inline-block",padding:"3px 10px",borderRadius:20,fontSize:10,fontWeight:600,letterSpacing:"0.04em",background:(CAT_COLORS[featured.category]||C.teal)+"18",color:CAT_COLORS[featured.category]||C.teal}}>{featured.category}</span>
              <span style={{fontSize:10,color:C.amber,fontWeight:600,letterSpacing:"0.1em"}}>FEATURED</span>
            </div>
            <h2 style={{fontFamily:"Montserrat",fontSize:"clamp(22px,2.5vw,30px)",fontWeight:700,lineHeight:1.2,marginBottom:12}}>{featured.title}</h2>
            <p style={{fontSize:14,color:C.w6,lineHeight:1.7,marginBottom:16}}>{featured.summary}</p>
            <div style={{display:"flex",alignItems:"center",gap:16}}>
              <span style={{fontSize:12,color:C.slate}}>{featured.date&&fmtDate(featured.date)} · {featured.read_time}</span>
              <span style={{fontSize:13,color:C.teal,fontWeight:600}}>Read article →</span>
            </div>
          </div>
          {ARTICLE_IMAGES[featured.slug]&&<div style={{flex:"0 0 360px",minHeight:220,position:"relative",overflow:"hidden",borderRadius:"0 16px 16px 0"}}><img src={ARTICLE_IMAGES[featured.slug]} alt="" style={{width:"100%",height:"100%",objectFit:"cover",display:"block"}}/><div style={{position:"absolute",inset:0,background:"linear-gradient(90deg,"+C.nc+" 0%,transparent 50%)"}}/></div>}
        </div>
      </div>}

      {/* Article grid */}
      {filtered.length>0?(<div className="responsive-grid-3">{filtered.map((a,i)=>{const cc=CAT_COLORS[a.category]||C.teal;return(<div key={a.slug} className={i<3?"fu"+(i+1):""} onClick={()=>onNav("article/"+a.slug)} style={{padding:0,borderRadius:12,background:C.nc,border:`1px solid ${C.w05}`,cursor:"pointer",transition:"all .25s",overflow:"hidden",display:"flex",flexDirection:"column"}} onMouseOver={e=>{e.currentTarget.style.borderColor=C.teal+"40";e.currentTarget.style.transform="translateY(-3px)";}} onMouseOut={e=>{e.currentTarget.style.borderColor=C.w05;e.currentTarget.style.transform="translateY(0)";}}>{ARTICLE_IMAGES[a.slug]&&<div style={{height:160,overflow:"hidden"}}><img src={ARTICLE_IMAGES[a.slug]} alt="" style={{width:"100%",height:"100%",objectFit:"cover",display:"block",transition:"transform .4s"}}/></div>}<div style={{padding:"18px 22px 0 22px",flex:1,display:"flex",flexDirection:"column"}}><div style={{marginBottom:10}}><span style={{display:"inline-block",padding:"3px 10px",borderRadius:20,fontSize:10,fontWeight:600,letterSpacing:"0.04em",background:cc+"18",color:cc}}>{a.category}</span></div><h3 style={{fontFamily:"Montserrat",fontSize:16,fontWeight:700,lineHeight:1.3,marginBottom:8}}>{a.title}</h3><p style={{fontSize:12,color:C.w4,lineHeight:1.6,marginBottom:14,flex:1,display:"-webkit-box",WebkitLineClamp:2,WebkitBoxOrient:"vertical",overflow:"hidden"}}>{a.summary}</p></div><div style={{padding:"14px 22px",borderTop:`1px solid ${C.w05}`,display:"flex",justifyContent:"space-between",alignItems:"center"}}><span style={{fontSize:10,color:C.slate}}>{a.date&&fmtDate(a.date)} · {a.read_time}</span><span style={{fontSize:12,color:C.teal,fontWeight:600}}>Read →</span></div></div>);})}</div>):(<div style={{textAlign:"center",padding:"48px 0"}}><p style={{fontSize:14,color:C.w4}}>No articles in this category yet.</p></div>)}
    </div>
  </div>);
}

// ═══════════════════════════════════════════════════════════════════
// PAGE: ARTICLE READER
// ═══════════════════════════════════════════════════════════════════
function ArticleReader({slug,onNav}){
  const article=ARTICLES.find(a=>a.slug===slug);
  if(!article) return(<div style={{maxWidth:720,margin:"0 auto",padding:"72px 24px",textAlign:"center"}}><p style={{color:C.w4}}>Article not found.</p><button onClick={()=>onNav("insight")} style={{marginTop:16,padding:"10px 20px",background:"transparent",border:`1px solid ${C.w1}`,borderRadius:8,color:C.w6,cursor:"pointer",fontSize:13,fontFamily:"Montserrat"}}>← Back to Insight</button></div>);

  const cc=CAT_COLORS[article.category]||C.teal;
  const paragraphs=article.body.includes("\n\n")?article.body.split("\n\n"):article.body.split("\n");
  const related=ARTICLES.filter(a=>a.slug!==slug&&a.category===article.category).slice(0,3);
  const moreArticles=related.length>=3?related:[...related,...ARTICLES.filter(a=>a.slug!==slug&&!related.find(r=>r.slug===a.slug)).slice(0,3-related.length)];

  const isHeading=(text)=>{
    const trimmed=text.trim();
    return trimmed.length<100&&!trimmed.endsWith('.')&&!trimmed.endsWith('?')&&!trimmed.endsWith('!')&&!trimmed.includes('\n')&&trimmed.length>3;
  };

  return(<div>
    <div style={{maxWidth:720,margin:"0 auto",padding:"48px 24px 72px"}}>
      {/* Back button */}
      <button onClick={()=>onNav("insight")} style={{display:"inline-flex",alignItems:"center",gap:6,padding:"8px 16px",background:"transparent",border:`1px solid ${C.w1}`,borderRadius:8,color:C.w6,cursor:"pointer",fontSize:12,fontFamily:"Open Sans",marginBottom:40,transition:"all .2s"}} onMouseOver={e=>{e.currentTarget.style.borderColor=C.teal;e.currentTarget.style.color=C.teal;}} onMouseOut={e=>{e.currentTarget.style.borderColor=C.w1;e.currentTarget.style.color=C.w6;}}>← Back to Insight</button>

      {/* Hero image */}
      {ARTICLE_IMAGES[slug]&&<div style={{marginBottom:32,borderRadius:12,overflow:"hidden",maxHeight:340}}><img src={ARTICLE_IMAGES[slug]} alt="" style={{width:"100%",height:"100%",objectFit:"cover",display:"block"}}/></div>}

      {/* Article header */}
      <div style={{marginBottom:40}}>
        <div style={{display:"flex",gap:12,alignItems:"center",marginBottom:16}}>
          <span style={{display:"inline-block",padding:"4px 12px",borderRadius:20,fontSize:11,fontWeight:600,letterSpacing:"0.04em",background:cc+"18",color:cc}}>{article.category}</span>
          {article.date&&<span style={{fontSize:12,color:C.slate}}>{fmtDate(article.date)}</span>}
          <span style={{fontSize:12,color:C.slate}}>{article.read_time}</span>
        </div>
        <h1 className="fu1" style={{fontFamily:"Montserrat",fontSize:"clamp(28px,4vw,40px)",fontWeight:700,lineHeight:1.12,letterSpacing:"-0.02em",marginBottom:12}}>{article.title}</h1>
        <p style={{fontSize:16,color:C.w6,lineHeight:1.6}}>{article.summary}</p>
        <div style={{width:48,height:3,background:C.teal,marginTop:24,borderRadius:2}}/>
      </div>

      {/* Article body */}
      <div style={{marginBottom:56}}>
        {paragraphs.filter(p=>p.trim().length>0).map((p,i)=>{
          if(isHeading(p)) return(<h2 key={i} style={{fontFamily:"Montserrat",fontSize:22,fontWeight:700,marginTop:48,marginBottom:16,lineHeight:1.3,color:C.w,borderLeft:`3px solid ${cc}`,paddingLeft:16}}>{p}</h2>);
          return(<p key={i} style={{fontSize:16,color:C.w8,lineHeight:1.9,marginBottom:24}}>{p}</p>);
        })}
      </div>

      {/* CTA */}
      <div style={{padding:28,borderRadius:14,background:`linear-gradient(135deg,${C.nc},${C.nl})`,border:`1px solid ${C.w1}`,textAlign:"center",marginBottom:56}}>
        <div style={{fontSize:10,color:C.teal,letterSpacing:"0.2em",fontWeight:600,marginBottom:8}}>PROVIO INTELLIGENCE</div>
        <h3 style={{fontFamily:"Montserrat",fontSize:18,fontWeight:700,marginBottom:8}}>Ready to assess your AI readiness?</h3>
        <p style={{fontSize:12,color:C.w4,maxWidth:400,margin:"0 auto 16px",lineHeight:1.5}}>Take the free diagnostic and receive a personalised report.</p>
        <div style={{display:"flex",gap:12,justifyContent:"center",flexWrap:"wrap"}}>
          <Btn primary onClick={()=>onNav("education")}>Education Intelligence</Btn>
          <Btn onClick={()=>onNav("business")}>Business Intelligence</Btn>
        </div>
      </div>

      {/* More articles */}
      {moreArticles.length>0&&<div>
        <SL text="More from PROVIO Insight"/>
        <h3 style={{fontFamily:"Montserrat",fontSize:20,fontWeight:700,marginBottom:24}}>Continue reading</h3>
        <div className="responsive-grid-3">
          {moreArticles.map((a,i)=>{const ac=CAT_COLORS[a.category]||C.teal;return(<div key={a.slug} onClick={()=>{onNav("article/"+a.slug);window.scrollTo({top:0,behavior:"smooth"});}} style={{padding:0,borderRadius:12,background:C.nc,border:`1px solid ${C.w05}`,cursor:"pointer",transition:"all .25s",overflow:"hidden",display:"flex",flexDirection:"column"}} onMouseOver={e=>{e.currentTarget.style.borderColor=C.teal+"40";e.currentTarget.style.transform="translateY(-3px)";}} onMouseOut={e=>{e.currentTarget.style.borderColor=C.w05;e.currentTarget.style.transform="translateY(0)";}}>{ARTICLE_IMAGES[a.slug]&&<div style={{height:130,overflow:"hidden"}}><img src={ARTICLE_IMAGES[a.slug]} alt="" style={{width:"100%",height:"100%",objectFit:"cover",display:"block"}}/></div>}<div style={{padding:"16px 20px 0 20px",flex:1,display:"flex",flexDirection:"column"}}><div style={{marginBottom:10}}><span style={{display:"inline-block",padding:"3px 10px",borderRadius:20,fontSize:9,fontWeight:600,letterSpacing:"0.04em",background:ac+"18",color:ac}}>{a.category}</span></div><h4 style={{fontFamily:"Montserrat",fontSize:14,fontWeight:700,lineHeight:1.3,marginBottom:6}}>{a.title}</h4><p style={{fontSize:11,color:C.w4,lineHeight:1.5,flex:1,display:"-webkit-box",WebkitLineClamp:2,WebkitBoxOrient:"vertical",overflow:"hidden"}}>{a.summary}</p></div><div style={{padding:"12px 20px",borderTop:`1px solid ${C.w05}`,display:"flex",justifyContent:"space-between",alignItems:"center"}}><span style={{fontSize:10,color:C.slate}}>{a.read_time}</span><span style={{fontSize:11,color:C.teal,fontWeight:600}}>Read →</span></div></div>);})}
        </div>
      </div>}
    </div>
  </div>);
}

// ═══════════════════════════════════════════════════════════════════
// APP — ROUTER
// ═══════════════════════════════════════════════════════════════════
export default function Provio(){
  const[page,setPage]=useState(()=>{
    const hash=window.location.hash.replace('#','');
    if(hash.startsWith('article/'))return 'article';
    const valid=['home','whatwedo','education','edu-survey','business','horizon','insight','article','about'];
    return valid.includes(hash)?hash:'home';
  });
  const[articleSlug,setArticleSlug]=useState(()=>{
    const hash=window.location.hash.replace('#','');
    return hash.startsWith('article/')?hash.replace('article/',''):'';
  });
  useSEO(page);
  const nav=id=>{if(id==="contact"){setPage("about");setTimeout(()=>{const el=document.getElementById("contact");if(el)el.scrollIntoView({behavior:"smooth"});},100);}else if(id.startsWith("article/")){const s=id.replace("article/","");setArticleSlug(s);setPage("article");window.history.replaceState(null,'','#article/'+s);window.scrollTo({top:0,behavior:"smooth"});}else{setArticleSlug("");setPage(id);window.scrollTo({top:0,behavior:"smooth"});}};

  return(<div style={{minHeight:"100vh",background:C.navy,color:C.w,fontFamily:"'Open Sans',system-ui,sans-serif"}}>
    <style>{CSS}</style>
    {page!=="edu-survey"&&<Nav active={page} onNav={nav}/>}
    <main role="main">
    {page==="home"&&<Home onNav={nav}/>}
    {page==="whatwedo"&&<WhatWeDo onNav={nav}/>}
    {page==="education"&&<Education onNav={nav} onStartSurvey={()=>nav("edu-survey")}/>}
    {page==="edu-survey"&&<EduSurvey onBack={()=>nav("education")}/>}
    {page==="business"&&<Business onNav={nav}/>}
    {page==="horizon"&&<HorizonMap onNav={nav}/>}
    {page==="insight"&&<InsightHub onNav={nav}/>}
    {page==="article"&&<ArticleReader slug={articleSlug} onNav={nav}/>}
    {page==="about"&&<About onNav={nav}/>}
    </main>
    {page!=="edu-survey"&&<Footer onNav={nav}/>}
  </div>);
}
